// CadastroEvento.jsx (parte completa do submit + states mínimos)
// Ajustado para enviar os campos EXATOS do banco:
// titulo, data, local, descricao, capacidade_total, mapa_url
// (vagas_restantes é calculado no BACK)

import React, { useState } from "react";

export default function CadastroEvento() {
  const [titulo, setTitulo] = useState("");
  const [data, setData] = useState("");
  const [local, setLocal] = useState("");
  const [descricao, setDescricao] = useState("");
  const [capacidadeTotal, setCapacidadeTotal] = useState(""); // input texto/number
  const [mapaUrl, setMapaUrl] = useState("");

  const [msg, setMsg] = useState("");
  const [erro, setErro] = useState("");

  async function handleSubmit(e) {
    e.preventDefault();
    setMsg("");
    setErro("");

    // ✅ validações básicas no front (a prova pede campos obrigatórios)
    if (!titulo.trim() || !data || !local.trim() || !descricao.trim() || !capacidadeTotal) {
      setErro("Preencha todos os campos obrigatórios.");
      return;
    }

    const capacidadeNumero = Number(capacidadeTotal);
    if (Number.isNaN(capacidadeNumero) || capacidadeNumero <= 0) {
      setErro("Capacidade total deve ser um número maior que 0.");
      return;
    }

    // ✅ payload com os NOMES DO BANCO
    const payload = {
      titulo: titulo.trim(),
      data, // yyyy-mm-dd
      local: local.trim(),
      descricao: descricao.trim(),
      capacidade_total: capacidadeNumero,
      mapa_url: mapaUrl.trim() ? mapaUrl.trim() : null,
    };

    try {
      const resp = await fetch("http://localhost:3001/eventos", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const dataResp = await resp.json();

      if (!resp.ok) {
        setErro(dataResp.erro || dataResp.error || "Erro ao cadastrar evento.");
        return;
      }

      setMsg("Cadastro concluído com sucesso!");

      // ✅ limpar formulário
      setTitulo("");
      setData("");
      setLocal("");
      setDescricao("");
      setCapacidadeTotal("");
      setMapaUrl("");
    } catch (err) {
      setErro("Falha ao conectar com a API. Verifique se o back está rodando.");
    }
  }

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Cadastro de Evento</h2>

      <form onSubmit={handleSubmit} style={{ display: "grid", gap: 10 }}>
        <label>
          Título:
          <input value={titulo} onChange={(e) => setTitulo(e.target.value)} />
        </label>

        <label>
          Data:
          <input type="date" value={data} onChange={(e) => setData(e.target.value)} />
        </label>

        <label>
          Local:
          <input value={local} onChange={(e) => setLocal(e.target.value)} />
        </label>

        <label>
          Descrição:
          <textarea value={descricao} onChange={(e) => setDescricao(e.target.value)} />
        </label>

        <label>
          Capacidade total:
          <input
            type="number"
            min="1"
            value={capacidadeTotal}
            onChange={(e) => setCapacidadeTotal(e.target.value)}
          />
        </label>

        <label>
          URL do mapa (opcional):
          <input value={mapaUrl} onChange={(e) => setMapaUrl(e.target.value)} />
        </label>

        <button type="submit">Cadastrar</button>

        {erro && <p style={{ color: "crimson" }}>{erro}</p>}
        {msg && <p style={{ color: "green" }}>{msg}</p>}
      </form>
    </div>
  );
}
